import{_ as i}from"./plugin-vue_export-helper-c27b6911.js";import{o as l,c as r,e}from"./app-01aedd85.js";const a={},t=e('<h1 id="多agent调用调度策略" tabindex="-1"><a class="header-anchor" href="#多agent调用调度策略" aria-hidden="true">#</a> 多Agent调用调度策略</h1><h3 id="一、多工具调用调度策略设计" tabindex="-1"><a class="header-anchor" href="#一、多工具调用调度策略设计" aria-hidden="true">#</a> 一、多工具调用调度策略设计</h3><ul><li><strong>意图路由调度:</strong> 基于意图理解结果，匹配工具库中的工具类型，过滤无关工具，缩小候选范围（如查<br> 询任务匹配检索工具，计算任务匹配计算器工具）。</li><li>**工具的拓扑排序：**分析工具间的依赖关系（如先检索数据、再计算、最后生成），构建有向无环图<br> （DAG），按拓扑顺序串行执行依赖工具，无依赖工具并行执行，降低延迟。</li><li>**工具的优先级：**划分工具优先级：核心工具（必选）优先调用，辅助工具（可选）延后调用；高优先级<br> 任务抢占资源，保证核心任务执行。</li><li>**参数的提前校验：**调用前校验工具入参是否完整、合法，提前拦截无效调用，避免资源浪费；缺失参数<br> 则主动反问用户补充。</li><li>**动态并发控制：**根据系统负载、工具QPS限制，动态调整并发调用数量，防止超出工具接口限流阈<br> 值。</li></ul><h3 id="二、agent评估体系" tabindex="-1"><a class="header-anchor" href="#二、agent评估体系" aria-hidden="true">#</a> 二、Agent评估体系</h3><p>一、Agent完整评估维度（全方位）</p><ol><li><p>任务性能维度<br> ◦ 任务完成率：成功达成用户目标的比例。<br> ◦ 规划合理性：步骤是否精简、顺序是否正确、无冗余操作。<br> ◦ 工具调用准确率：正确调用工具、参数合规的比例。</p></li><li><p>生成质量维度<br> ◦ 幻觉发生率：事实错误、编造内容的占比。<br> ◦ 多轮一致性：前后回答无矛盾、不遗忘历史约束。</p></li></ol><p>◦ 流畅度与可读性：语言通顺、符合人类表达习惯。</p><ol start="3"><li>鲁棒性维度<br> ◦ 对抗输入容错率：面对模糊、错误、恶意指令的应对能力。<br> ◦ 异常恢复能力：故障后重新规划、完成任务的能力。</li><li>工程性能维度<br> ◦ 响应延迟、并发吞吐量、显存占用。</li><li>安全合规维度<br> ◦ 有害内容输出率、隐私泄露率、违规指令拒绝率。</li></ol><h3 id="三、模块化设计核心架构" tabindex="-1"><a class="header-anchor" href="#三、模块化设计核心架构" aria-hidden="true">#</a> 三、模块化设计核心架构</h3><p>一、模块化设计核心架构<br> Modular Agent采用“解耦+协同”设计，拆分为5大核心模块，各模块独立迭代、通过标准化接口通<br> 信：</p><ol><li>意图理解模块：解析用户需求、提取关键参数、识别任务类型，将自然语言转化为结构化任务指<br> 令。</li><li>规划决策模块：核心模块，基于任务指令拆解子任务、确定执行顺序、选择调用工具，生成可执行<br> 的步骤化规划。</li><li>工具执行模块：负责调用外部工具（API、数据库、向量库、计算器），接收工具返回结果。</li><li>记忆管理模块：存储短期记忆（当前对话、中间结果）、长期记忆（历史任务、用户偏好），支持<br> 记忆检索、压缩、更新。</li><li>反思校验模块：评估子任务执行结果、校验逻辑合理性、判断是否需要重新规划，修正错误决策。</li></ol><p>基于ReAct+反思迭代闭环，流程如下：</p><ol><li>任务接收与解析：用户query输入→意图理解模块提取实体、约束、目标→输出结构化任务描述。</li><li>全局规划生成：规划模块调取记忆模块的历史信息，结合任务描述，将复杂任务拆解为有序子任务<br> （如“查询数据→计算分析→生成报告”），确定子任务依赖关系。</li><li>子任务分步执行：按规划顺序执行子任务，工具模块调用对应能力，执行结果存入短期记忆；无依<br> 赖子任务支持并行执行，提升效率。</li><li>反思与迭代：每完成一个子任务，反思模块校验结果是否符合预期、是否缺失信息、是否存在逻辑<br> 错误；若失败则触发重新规划（调整子任务、更换工具），若成功则推进下一子任务。</li><li>任务收尾与总结：所有子任务完成后，聚合记忆模块中的中间结果，生成最终答案，同步更新长期<br> 记忆。</li></ol>',13),n=[t];function o(h,d){return l(),r("div",null,n)}const s=i(a,[["render",o],["__file","20、多Agent调用策略.html.vue"]]);export{s as default};
